import re

def scrub_logs(log_lines):
    # Define patterns to identify API keys, then replace with [REDACTED]
    patterns = [r"key=(?P<key_value>[a-zA-Z0-9_-]+)", r"auth_token=(?P<key_value>[a-zA-Z0-9_-]+)", r"api_key=(?P<key_value>[a-zA-Z0-9_-]+)", r"api_secret=(?P<key_value>[a-zA-Z0-9_-]+)"]
    for log_line in log_lines:
        for pattern in patterns:
            log_line = re.sub(pattern, lambda m: f"{m.group('{key_value}')}=[REDACTED]", log_line)
    return log_lines
